from openai import OpenAI
client = OpenAI()

def detect_sandbox_violations(run):
    if run.status == 'completed':
        for tool_call in run.required_action.submit_tool_outputs.tool_calls:
            if tool_call.type == 'code_interpreter':
                if 'sandbox_violation' in tool_call.code_interpreter.logs.lower():
                    return {'alert': 'Sandbox violation detected', 'severity': 'high'}
    return None

import openai

def detect_irrelevant_files(thread):
    messages = client.beta.threads.messages.list(thread_id=thread.id)
    for msg in messages.data:
        if msg.tool_calls:
            for tc in msg.tool_calls:
                if tc.type == 'file_search' and hasattr(tc.file_search, 'score'):
                    if tc.file_search.score < 0.7:
                        return {'alert': f'Low relevance file_search: {tc.id}', 'score': tc.file_search.score}
    return None

const OpenAI = require('openai');
const openai = new OpenAI();

async function detectContextOverflow(threadId) {
  const messages = await openai.beta.threads.messages.list(threadId);
  if (messages.data.length > 80) {
    return {
      alert: 'Thread context approaching limits',
      messageCount: messages.data.length,
      severity: 'medium'
    };
  }
  return null;
}

