from vex import Vex
vex = Vex(api_key="your-vex-key")

@vex.verifier('openai-assistants-drift')
def monitor_assistant_run(run: dict) -> dict:
    issues = []

    # Check thread length
    if run.get('thread', {}).get('message_count', 0) > 80:
        issues.append({'type': 'context_overflow', 'severity': 'high'})

    # Check tool call validity
    for tool in run.get('required_action', {}).get('tool_calls', []):
        if tool['type'] == 'code_interpreter' and 'sandbox_error' in tool:
            issues.append({'type': 'sandbox_violation', 'severity': 'critical'})

    return {'issues': issues, 'run_id': run['id']}

